import { useState } from "react";
import { useData } from "../contexts/DataContext";
import { toast } from "sonner";

export default function Chatbot() {
  const { chatbot, setChatbot } = useData();
  const [form, setForm] = useState(chatbot);
  const [loading, setLoading] = useState(false);

  const set = (k, v) => setForm({ ...form, [k]: v });

  const handleSave = () => {
    setLoading(true);
    setTimeout(() => {
      setChatbot(form);
      toast.success("Perubahan berhasil disimpan");
      setLoading(false);
    }, 600);
  };

  return (
    <div className="min-h-screen bg-gray-50 p-8" data-testid="chatbot-page">
      <h1 className="text-4xl font-black text-gray-900 mb-8">Kelola Chatbot</h1>
      <div className="flex gap-6 items-start">
        {/* Left card — pesan sambutan & fallback */}
        <div className="flex-1 bg-white rounded-2xl shadow-sm border border-gray-100 p-7 space-y-5">
          {/* Greeting */}
          <div>
            <div className="font-bold text-gray-900 text-base mb-0.5">Pesan Sambutan</div>
            <div className="text-xs text-gray-400 mb-2">Teks Sambutan</div>
            <textarea
              data-testid="greeting-input"
              rows={5}
              className="w-full rounded-xl border border-gray-200 bg-gray-50 p-4 text-gray-800 text-base resize-none focus:outline-none focus:ring-2 focus:ring-amber-400 transition"
              value={form.greeting}
              onChange={(e) => set("greeting", e.target.value)}
            />
          </div>
          {/* Fallback */}
          <div>
            <div className="text-xs text-gray-400 mb-2">Respon Jika Tidak Di pahami</div>
            <textarea
              data-testid="fallback-input"
              rows={6}
              className="w-full rounded-xl border border-gray-200 bg-gray-50 p-4 text-gray-800 text-base resize-none focus:outline-none focus:ring-2 focus:ring-amber-400 transition"
              value={form.fallback}
              onChange={(e) => set("fallback", e.target.value)}
            />
          </div>
        </div>

        {/* Right card — pengaturan */}
        <div className="w-72 bg-white rounded-2xl shadow-sm border border-gray-100 p-7">
          <div className="font-bold text-gray-900 text-xl mb-6">Pengaturan</div>

          <div className="flex items-center justify-between">
            <div>
              <div className="font-bold text-gray-900 text-base">Auto-reply aktif</div>
              <div className="text-xs text-gray-400 mt-0.5">Balas otomatis 24 jam</div>
            </div>

            {/* Custom Toggle — sama persis seperti gambar */}
            <button
              type="button"
              role="switch"
              aria-checked={form.enabled}
              data-testid="chatbot-toggle"
              onClick={() => set("enabled", !form.enabled)}
              className={`relative inline-flex items-center w-14 h-7 rounded-full border-2 transition-colors duration-200 focus:outline-none ${
                form.enabled
                  ? "bg-amber-400 border-amber-400"
                  : "bg-gray-200 border-gray-200"
              }`}
            >
              <span
                className={`inline-block w-5 h-5 bg-white rounded-full shadow transform transition-transform duration-200 ${
                  form.enabled ? "translate-x-7" : "translate-x-0.5"
                }`}
              />
            </button>
          </div>
        </div>
      </div>

      {/* Save button */}
      <div className="mt-6 flex justify-end">
        <button
          onClick={handleSave}
          disabled={loading}
          data-testid="save-chatbot-btn"
          style={{
            background: "#F5BC00",
            color: "#fff",
            border: "none",
            borderRadius: 8,
          }}
          className="h-11 px-8 text-sm font-semibold disabled:opacity-60 disabled:cursor-not-allowed"
        >
          {loading ? "Menyimpan..." : "Simpan Perubahan"}
        </button>
      </div>
    </div>
  );
}
